import re
from base64 import b16decode,b16encode


class EncryptionKey:
    def __init__(self):
        self._key = "0278b89e93d3a354f681e4d774be29c4354b0e9f79093bdce493de93783a452a"

    def get_key(self):
        return self._key


class Encryption:
    def __init__(self, encryptionKey=EncryptionKey()):
        self.key = encryptionKey.get_key()

    def encrypt(self, string):
        encoded = b16encode(string)
        crypt = bytearray(len(encoded))

        for i in range(0, len(crypt)):
            crypt[i] ^= int(re.match(r'.{2}', self.key)[0], 16)

            # XOR is a bitwise operator
            # ^ means "bitwise exclusive or". A^B = 0 if A=B and vice versa. 
            # If a 1 in both fields, 0, else 1.
        return crypt
